import fs from 'fs'
import path from 'path'
import matter from 'gray-matter'
import readingTime from 'reading-time'
import type { ArticleSummary } from '@/components/blog/article-card'

const CONTENT_DIR = path.join(process.cwd(), 'content', 'articles')

export interface Article extends ArticleSummary {
  content: string
}

function getArticleFiles(): string[] {
  if (!fs.existsSync(CONTENT_DIR)) return []
  const files: string[] = []
  function walk(dir: string) {
    const entries = fs.readdirSync(dir, { withFileTypes: true })
    for (const entry of entries) {
      const full = path.join(dir, entry.name)
      if (entry.isDirectory()) {
        walk(full)
      } else if (entry.name.endsWith('.mdx') || entry.name.endsWith('.md')) {
        // Store as relative path from CONTENT_DIR (e.g. 'ai/linear-regression-python.mdx')
        files.push(path.relative(CONTENT_DIR, full))
      }
    }
  }
  walk(CONTENT_DIR)
  return files
}

export async function getAllArticles(): Promise<ArticleSummary[]> {
  const files = getArticleFiles()
  const articles = files.map((file) => {
    // slug = filename only (no subdirectory), used for URL
    const slug = file.replace(/\.(mdx|md)$/, '').split('/').pop() || file
    // fullPath includes subdirectory for file reading
    const fullPath = path.join(CONTENT_DIR, file)
    const raw = fs.readFileSync(fullPath, 'utf-8')
    const { data, content } = matter(raw)
    const rt = readingTime(content)

    return {
      slug,
      title: data.title || slug,
      excerpt: data.excerpt || '',
      category: data.category || 'cs-fundamentals',
      tags: data.tags || [],
      hero: data.hero || null,
      author: data.author || 'MAIY Tech Hub',
      readingTime: Math.ceil(rt.minutes),
      publishedAt: data.date || new Date().toISOString(),
    } as ArticleSummary
  })

  return articles.sort(
    (a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime()
  )
}

export async function getRecentArticles(limit = 6): Promise<ArticleSummary[]> {
  const all = await getAllArticles()
  return all.slice(0, limit)
}

export async function getFeaturedArticles(): Promise<ArticleSummary[]> {
  return getAllArticles()
}

export async function getArticleBySlug(slug: string): Promise<Article | null> {
  // slug may be "ai/linear-regression-python" (subdirectory/name) or just "name"
  // Try direct match first, then fall back to recursive search
  let filePath: string | null = null

  // 1. Try direct path relative to CONTENT_DIR (slug includes subdir)
  const direct = path.join(CONTENT_DIR, `${slug}.mdx`)
  if (fs.existsSync(direct)) {
    filePath = direct
  }

  // 2. Fallback: search recursively for a file whose name (without dir) matches slug
  function find(name: string, dir: string): boolean {
    try {
      const entries = fs.readdirSync(dir, { withFileTypes: true })
      for (const entry of entries) {
        const full = path.join(dir, entry.name)
        if (entry.isDirectory()) {
          if (find(name, full)) return true
        } else {
          const base = entry.name.replace(/\.(mdx|md)$/, '')
          if (base === name) {
            filePath = full
            return true
          }
        }
      }
    } catch {
      // ignore read errors
    }
    return false
  }
  if (!filePath) find(slug, CONTENT_DIR)

  if (!filePath) return null

  const raw = fs.readFileSync(filePath, 'utf-8')
  const { data, content } = matter(raw)
  const rt = readingTime(content)

  return {
    slug,
    title: data.title || slug,
    excerpt: data.excerpt || '',
    category: data.category || 'cs-fundamentals',
    tags: data.tags || [],
    hero: data.hero || null,
    author: data.author || 'MAIY Tech Hub',
    readingTime: Math.ceil(rt.minutes),
    publishedAt: data.date || new Date().toISOString(),
    content,
  }
}

export async function getArticlesByCategory(
  category: string
): Promise<ArticleSummary[]> {
  const all = await getAllArticles()
  return all.filter((a) => a.category === category)
}

export async function getAllSlugs(): Promise<string[]> {
  return getArticleFiles().map((f) => f.replace(/\.(mdx|md)$/, ''))
}

