export const dynamic = 'force-static'

interface Props {
  params: { slug: string[] }
}

export async function generateStaticParams() {
  const slugs = await getAllSlugs()
  // slugs are like 'ai/linear-regression-python' — split into segments for [...slug]
  return slugs.map((slug) => ({ slug: slug.split('/') }))
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const slugString = params.slug.join('/')
  const article = await getArticleBySlug(slugString)
  if (!article) return { title: 'Không tìm thấy' }
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'https://maiytechhub.com'
  return {
    title: article.title,
    description: article.excerpt,
    keywords: article.tags,
    alternates: {
      canonical: `${siteUrl}/articles/${article.slug}`,
    },
    openGraph: {
      type: 'article',
      title: article.title,
      description: article.excerpt,
      url: `${siteUrl}/articles/${article.slug}`,
      siteName: 'MAIY Tech Hub',
      locale: 'vi_VN',
      images: article.hero ? [{ url: article.hero, width: 1200, height: 630, alt: article.title }] : [],
      publishedTime: article.publishedAt,
      tags: article.tags,
    },
    twitter: {
      card: 'summary_large_image',
      title: article.title,
      description: article.excerpt,
      images: article.hero ? [article.hero] : [],
    },
  }
}

