import { useState, useRef } from 'react'
import { Send, CheckCircle, PartyPopper, Loader2, Mail, ArrowRight } from 'lucide-react'

export function NewsletterForm() {
  const [email, setEmail] = useState('')
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle')
  const [errorMsg, setErrorMsg] = useState('')
  const [focused, setFocused] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!email) return

    setStatus('loading')
    setErrorMsg('')

    try {
      const res = await fetch('/api/newsletter', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      })
      const data = await res.json()

      if (res.ok) {
        setStatus('success')
        setEmail('')
        setTimeout(() => setStatus('idle'), 5000)
      } else {
        setStatus('error')
        setErrorMsg(data.error || 'Có lỗi xảy ra')
        setTimeout(() => setStatus('idle'), 4000)
      }
    } catch {
      setStatus('error')
      setErrorMsg('Không thể kết nối, vui lòng thử lại.')
      setTimeout(() => setStatus('idle'), 4000)
    }
  }

  if (status === 'success') {
    return (
      <div className="flex flex-col items-center gap-3 animate-fade-in">
        <div className="flex items-center gap-3 text-white">
          <CheckCircle className="h-6 w-6 text-emerald-400" />
          <span className="text-lg font-semibold">Đăng ký thành công!</span>
        </div>
        <div className="flex items-center gap-2 text-white/60 text-sm">
          <span>Cảm ơn bạn, bài viết mới sẽ gửi đến email tuần này</span>
          <PartyPopper className="h-4 w-4 text-amber-400" />
        </div>
      </div>
    )
  }

  return (
    <div className="w-full max-w-md mx-auto">
      {/* Name + Email row on desktop */}
      <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3">
        {/* Name input */}
        <div className="relative flex-1">
          <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none">
            <Mail className="h-4 w-4 text-white/40" />
          </div>
          <input
            type="text"
            placeholder="Tên của bạn"
            disabled={status === 'loading'}
            className="w-full pl-9 pr-4 py-3 rounded-xl bg-white/10 backdrop-blur-sm text-white placeholder:text-white/35 border border-white/15 focus:outline-none focus:border-violet-400/60 focus:bg-white/15 transition-all duration-300 disabled:opacity-50 text-sm"
          />
        </div>

        {/* Email input */}
        <div className="relative flex-1">
          <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none">
            <span className="text-white/40 text-sm">@</span>
          </div>
          <input
            type="email"
            ref={inputRef}
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onFocus={() => setFocused(true)}
            onBlur={() => setFocused(false)}
            placeholder="email@example.com"
            required
            disabled={status === 'loading'}
            className="w-full pl-9 pr-4 py-3 rounded-xl bg-white/10 backdrop-blur-sm text-white placeholder:text-white/35 border border-white/15 focus:outline-none focus:border-violet-400/60 focus:bg-white/15 transition-all duration-300 disabled:opacity-50 text-sm"
          />
          {/* Focus glow ring */}
          <div
            className={`absolute inset-0 rounded-xl pointer-events-none transition-opacity duration-300 ${focused ? 'opacity-100' : 'opacity-0'}`}
            style={{ boxShadow: '0 0 0 2px #8b5cf660, inset 0 0 20px #8b5cf610' }}
          />
        </div>

        {/* Submit button */}
        <button
          type="submit"
          disabled={status === 'loading' || !email}
          className="relative flex items-center justify-center gap-2 px-6 py-3 rounded-xl font-semibold text-sm overflow-hidden group disabled:opacity-50 flex-shrink-0"
          style={{
            background: 'linear-gradient(135deg, #7c3aed, #6366f1)',
            boxShadow: '0 4px 20px #7c3aed40',
          }}
        >
          {/* Hover shimmer */}
          <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300"
            style={{ background: 'linear-gradient(135deg, #8b5cf6, #818cf8, #a78bfa)', backgroundSize: '200% 200%', animation: 'shimmer 1.5s ease infinite' }} />
          <span className="relative flex items-center gap-2">
            {status === 'loading' ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <>
                <Send className="h-4 w-4" />
                <span>Đăng ký</span>
                <ArrowRight className="h-3.5 w-3.5 transition-transform duration-200 group-hover:translate-x-1" />
              </>
            )}
          </span>
        </button>
      </form>

      {/* Error */}
      {status === 'error' && (
        <p className="text-red-400/90 text-xs text-center mt-2 flex items-center justify-center gap-1.5">
          <span className="w-1 h-1 rounded-full bg-red-400" />
          {errorMsg}
        </p>
      )}

      {/* Privacy note */}
      <p className="text-white/25 text-xs text-center mt-3">
        Cam kết không spam. Hủy đăng ký bất kỳ lúc nào.
      </p>

      <style>{`
        @keyframes shimmer {
          0% { background-position: 200% center; }
          100% { background-position: -200% center; }
        }
      `}</style>
    </div>
  )
}

