const ADMIN_COOKIE = 'maiy_admin_token'
const ADMIN_PASSWORD = process.env.ADMIN_PASSWORD || 'maiy2026'

export async function verifyAdmin(token: string): Promise<boolean> {
  // Simple token check — replace with proper JWT/session in production
  return token === ADMIN_PASSWORD
}

export async function getAdminSession(): Promise<boolean> {
  const cookieStore = await cookies()
  const token = cookieStore.get(ADMIN_COOKIE)?.value
  if (!token) return false
  return verifyAdmin(token)
}

export async function loginAdmin(password: string): Promise<boolean> {
  if (password !== ADMIN_PASSWORD) return false
  const cookieStore = await cookies()
  cookieStore.set(ADMIN_COOKIE, ADMIN_PASSWORD, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 60 * 60 * 24 * 7, // 1 week
    path: '/',
  })
  return true
}

export async function logoutAdmin(): Promise<void> {
  const cookieStore = await cookies()
  cookieStore.delete(ADMIN_COOKIE)
}

